using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Storage.ValueConversion;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Keep the old property name so existing documents are found.
            b.HasDiscriminator<string>("Discriminator").HasValue<Blog>("Blog");

            // Breaking change: id is no longer synthesized as "{Discriminator}|{Key}".
            // In EF Core 9 the entity's Id property maps directly to JSON "id".
            // Use a value converter to preserve the "Blog|{key}" format on disk.
            b.Property(e => e.Id).HasConversion(
                id => "Blog|" + id,
                id => id.StartsWith("Blog|") ? id.Substring(5) : id);

            // Breaking change: HasIndex() now throws for Cosmos (was silently ignored).
            // Removed: b.HasIndex(e => e.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

